#include <string.h>

static inline int em_check_ros1_param_hijack(const char *payload) {
    if (payload == NULL) return 0;

    // Verify this is an XML-RPC request
    if (strstr(payload, "<methodCall>") == NULL &&
        strstr(payload, "<?xml") == NULL) return 0;

    // Must contain setParam method
    const char *method_start = strstr(payload, "<methodName>");
    if (method_start == NULL) return 0;
    if (strstr(method_start, "setParam") == NULL) return 0;

    // Safety-critical parameter names
    static const char *critical_params[] = {
        "safety_enabled",
        "max_velocity",
        "max_acceleration",
        "max_speed",
        "emergency_stop",
        "collision_detection",
        "collision_threshold",
        "speed_limit",
        "force_limit",
        "payload_mass",
        "joint_limit",
        "workspace_limit",
        "protective_stop",
        "speed_scaling",
        "robot_enabled",
        "use_sim_time"
    };
    static const int num_params = sizeof(critical_params) / sizeof(critical_params[0]);

    int i;
    for (i = 0; i < num_params; i++) {
        if (strstr(payload, critical_params[i]) != NULL) {
            return 1;
        }
    }

    return 0;
}
